/**
 * CIIU (Clasificacion Industrial Internacional Uniforme) activity codes.
 *
 * Source: https://github.com/Startup-Colombia/CIIU
 * Contains 500 4-digit activity codes across 21 sectors.
 * Used by the onboarding wizard's searchable combobox for economic activity selection.
 */

export interface CiiuCode {
  /** 4-digit CIIU activity code (e.g., "6201") */
  code: string;
  /** Spanish description of the economic activity */
  description: string;
  /** Single letter sector code (e.g., "J" for Information and Communication) */
  sector: string;
}

